import graphene
from graphene import ObjectType, String, Boolean, Int, Mutation, Schema
from graphql import GraphQLError

class User(ObjectType):
    id = String()
    username = String()
    email = String()
    bio = String()
    role = String()
    is_admin = Boolean()
    credits = Int()
    subscription_tier = String()

class UpdateUserProfile(Mutation):
    class Arguments:
        username = String()
        email = String()
        bio = String()
        role = String()
        is_admin = Boolean()
        credits = Int()
        subscription_tier = String()

    user = graphene.Field(lambda: User)

    def mutate(self, info, **kwargs):
        # Get authenticated user from context
        user = info.context.get('user')
        if not user:
            raise GraphQLError("Authentication required")
        
        # Check if user is updating their own profile or is admin
        if not user.get('is_admin') and user.get('id') != kwargs.get('id'):
            raise GraphQLError("Permission denied")
        
        # Validate input fields
        allowed_fields = ['username', 'email', 'bio', 'role', 'is_admin', 'credits', 'subscription_tier']
        for field in kwargs:
            if field not in allowed_fields:
                raise GraphQLError(f"Invalid field: {field}")
        
        # Validate email format if provided
        if 'email' in kwargs and kwargs['email']:
            if '@' not in kwargs['email']:
                raise GraphQLError("Invalid email format")
        
        # Validate credits if provided
        if 'credits' in kwargs and kwargs['credits'] is not None:
            if kwargs['credits'] < 0:
                raise GraphQLError("Credits cannot be negative")
        
        # Validate subscription tier if provided
        if 'subscription_tier' in kwargs and kwargs['subscription_tier']:
            valid_tiers = ['free', 'basic', 'premium', 'enterprise']
            if kwargs['subscription_tier'] not in valid_tiers:
                raise GraphQLError("Invalid subscription tier")
        
        # Simulate database update
        updated_user = {
            'id': user.get('id'),
            'username': kwargs.get('username', user.get('username')),
            'email': kwargs.get('email', user.get('email')),
            'bio': kwargs.get('bio', user.get('bio')),
            'role': kwargs.get('role', user.get('role')),
            'is_admin': kwargs.get('is_admin', user.get('is_admin')),
            'credits': kwargs.get('credits', user.get('credits')),
            'subscription_tier': kwargs.get('subscription_tier', user.get('subscription_tier'))
        }
        
        return UpdateUserProfile(user=updated_user)

class Mutation(ObjectType):
    update_user_profile = UpdateUserProfile.Field()

schema = Schema(mutation=Mutation)